    // This pattern arises when computing the final address after a range.
    if (CastOpc == Instruction::PtrToInt && isa<GEPOperator>(Op)) {
      GEPOperator *GEP = cast<GEPOperator>(Op);
      Value *Ptr = GEP->getPointerOperand();
      Type *ElTy = GEP->getSourceElementType();
      if (!ElTy->isIntegerTy(8)) // Must be i8 GEP for byte offset arithmetic
        return nullptr;

      Value *Idx = GEP->getOperand(1);
      if (!Idx->getType()->isIntegerTy())
        return nullptr;

      // Look for: sub i64 %end.addr, %ptr.addr
      auto *Sub = dyn_cast<BinaryOperator>(Idx);
      if (!Sub || Sub->getOpcode() != Instruction::Sub)
        return nullptr;

      Value *EndAddr = Sub->getOperand(0);
      Value *PtrAddr = Sub->getOperand(1);

      // We require that %ptr.addr = ptrtoint %ptr to i64
      auto *PtrToInt = dyn_cast<PtrToIntInst>(PtrAddr);
      if (!PtrToInt || PtrToInt->getPointerOperand() != Ptr || PtrToInt->getType() != EndAddr->getType())
